  1167→        sessions: string;
  1168→        block: string[];
  1169→        blockReason: string;
  1170→        summary: boolean; // commander sets this from --no-summary
  1171→        maxLogLines: number;
  1172→        quiet?: boolean;
  1173→      }>();
  1174→
  1175→      const sessionsPath = expandHome(opts.sessions);
  1176→      const blockPatterns = opts.block.map((p) => new RegExp(p));
  1177→      const noSummary = !opts.summary;
  1178→
  1179→      // Read stdin
  1180→      let raw: string;
  1181→      try {
  1182→        raw = await readStdin();
  1183→      } catch (err) {
  1184→        process.stderr.write(`claude-hook-handler: failed to read stdin: ${err}\n`);
  1185→        process.exit(1);
  1186→      }
  1187→
  1188→      let input: HookInput;
  1189→      try {
  1190→        input = JSON.parse(raw) as HookInput;
  1191→      } catch {
  1192→        process.stderr.write(
