  1232→
  1233→          // 4. Persist state (after appendSessionLog so pendingToolUses mutations are saved)
  1234→          await writeStateToDb(db, state);
  1235→
  1236→          commitFiles(sessionsPath, [sessionsPath, ...logPaths], buildCommitMessage(input, state));
