  1248→      }
  1249→
  1250→      // JSON response to stdout
  1251→      process.stdout.write(
  1252→        JSON.stringify(buildResponse(blocked, opts.blockReason)) + "\n",
  1253→      );
  1254→    });
  1255→
  1256→  await program.parseAsync();
  1257→}
  1258→
  1259→main().catch((err: Error) => {
